insert into hatsune_description values (1002501, 10025, 1, '在活动中，可以观看特别的故事。\\n活动剧情会根据活动关卡的通关进度解锁。');
insert into hatsune_description values (1002502, 10025, 1, '完成活动限定的任务后，会有\\n可解锁的角色登场。请在活动期间\\n努力完成任务吧。');
insert into hatsune_description values (1002503, 10025, 1, '在VERY HARD难度中，还会出现强大的BOSS。\\n「VERY HARD」BOSS，1天只可以讨伐1只。\\n请在做好了充足的准备后，再去挑战吧。');
insert into hatsune_description values (1002504, 10025, 1, '讨伐证可以用来兑换报酬。\\n报酬也包括在活动中登场的部分角色的记忆碎片。\\n收集记忆碎片将角色变为自己的同伴吧。');
insert into hatsune_description values (1002505, 10025, 3, '特别关卡是战斗模式会发生3个阶段式变化的关卡。\\n在这里获得更加丰厚的报酬和任务报酬吧。\\n活动期间只能讨伐1只，所以，请好好研究编组进行挑战。');
insert into hatsune_description values (1002506, 10025, 3, '在Exhibition模式下可以多次挑战SPECIAL BOSS。\\n此外，也可以保存战斗记录来进行回顾，\\n请寻找适合自己的攻略方法，尝试各种各样的编组吧。');
insert into hatsune_description values (1002507, 10025, 4, '挑战活动关卡和BOSS时，\\n会触发信赖度章节。根据对话的结果，能提升信赖度，\\n当信赖度达到一定程度时，还能获得礼物。');
insert into hatsune_description values (1002601, 10026, 1, '在活动中，可以观看特别的故事。\\n活动剧情会根据活动关卡的通关进度解锁。');
insert into hatsune_description values (1002602, 10026, 1, '完成活动限定的任务后，会有\\n可解锁的角色登场。请在活动期间\\n努力完成任务吧。');
